const AWS = require('aws-sdk');
const https = require('https');

const dynamodb = new AWS.DynamoDB.DocumentClient();

function httpRequest(url, method, body, headers = {}) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const req = https.request(
      url,
      {
        method,
        headers: {
          'Content-Type': 'application/json',
          ...(data ? { 'Content-Length': Buffer.byteLength(data) } : {}),
          ...headers,
        },
      },
      (res) => {
        let responseBody = '';
        res.on('data', (chunk) => {
          responseBody += chunk;
        });
        res.on('end', () => {
          let parsed = responseBody;
          try {
            parsed = responseBody ? JSON.parse(responseBody) : {};
          } catch (_) {}
          resolve({
            statusCode: res.statusCode,
            body: parsed,
          });
        });
      }
    );

    req.on('error', reject);

    if (data) {
      req.write(data);
    }

    req.end();
  });
}

async function processOrder(order) {
  const paymentApiUrl = process.env.PAYMENT_API_URL;
  const ordersTable = process.env.ORDERS_TABLE;

  const paymentResponse = await httpRequest(
    `${paymentApiUrl}/charge`,
    'POST',
    {
      orderId: order.orderId,
      customerId: order.customerId,
      amount: order.amount,
      currency: order.currency || 'USD',
      paymentMethod: order.paymentMethod,
    },
    process.env.PAYMENT_API_KEY
      ? { Authorization: `Bearer ${process.env.PAYMENT_API_KEY}` }
      : {}
  );

  const status =
    paymentResponse.statusCode >= 200 && paymentResponse.statusCode < 300
      ? 'PAID'
      : 'PAYMENT_FAILED';

  await dynamodb
    .update({
      TableName: ordersTable,
      Key: { orderId: order.orderId },
      UpdateExpression:
        'SET #status = :status, paymentResponse = :paymentResponse, updatedAt = :updatedAt',
      ExpressionAttributeNames: {
        '#status': 'status',
      },
      ExpressionAttributeValues: {
        ':status': status,
        ':paymentResponse': paymentResponse.body,
        ':updatedAt': new Date().toISOString(),
      },
    })
    .promise();
}

exports.handler = async (event) => {
  const records = event.Records || [];

  await Promise.all(
    records.map(async (record) => {
      try {
        const order = JSON.parse(record.body);
        await processOrder(order);
      } catch (error) {
        console.error('Failed to process record', {
          messageId: record.messageId,
          error: error.message,
          stack: error.stack,
        });
      }
    })
  );

  return {
    statusCode: 200,
    processed: records.length,
  };
};